openscad:
case_dia = 40; // [30:1:60]
case_height = 9; // [6:1:15]
dial_thickness = 1.5;
marker_height = 1.2;
hand_thick = 1.2;
date_win_w = 6;
date_win_h = 4;
hour_angle = 300;
minute_angle = 40;
second_angle = 150;
$fn = 60;

module watch_case() {
    color("silver")
    difference() {
        cylinder(d=case_dia+4, h=case_height);
        translate([0,0,1.5])
            cylinder(d=case_dia, h=case_height);
    }
    color("silver")
    translate([0,0,case_height-1.5])
        cylinder(d=case_dia+2, h=1.5);
}

module dial() {
    color("white")
    cylinder(d=case_dia-2, h=dial_thickness);
}

module hour_markers() {
    color("black")
    for (i = [0:11]) {
        rotate([0,0,i*30])
            translate([case_dia/2-5, -0.6, dial_thickness])
                cube([4, 1.2, marker_height]);
    }
}

module date_window() {
    color("white")
    translate([case_dia/2-9, -date_win_h/2, dial_thickness-0.1])
        cube([date_win_w, date_win_h, 1]);
    color("black")
    translate([case_dia/2-8.5, -1.2, dial_thickness+0.3])
        linear_extrude(0.8)
            text("31", size=2.8, font="Arial");
}

module hands() {
    // hour hand
    color("black")
    rotate([0,0,hour_angle])
        translate([-1.5, -hand_thick/2, dial_thickness+0.1])
            cube([case_dia/2-10, hand_thick, 1]);
    // minute hand
    color("black")
    rotate([0,0,minute_angle])
        translate([-1.2, -hand_thick/2, dial_thickness+0.2])
            cube([case_dia/2-7, hand_thick, 1]);
    // second hand
    color("red")
    rotate([0,0,second_angle])
        translate([-1, -0.4, dial_thickness+0.3])
            cube([case_dia/2-6, 0.8, 0.8]);
    // center pin
    color("black")
    translate([0,0,dial_thickness+0.4])
        cylinder(d=2.5, h=1.5);
}

union() {
    watch_case();
    translate([0,0,1.5])
        dial();
    translate([0,0,1.5])
        hour_markers();
    translate([0,0,1.5])
        date_window();
    translate([0,0,1.5])
        hands();
}
